#include <bits/stdc++.h>
using namespace std;

int getMaximumTeamSize(const vector<int>& startTime, const vector<int>& endTime) {
    int n = startTime.size();
    if (n == 0) return 0;

    vector<int> S = startTime;
    vector<int> E = endTime;
    sort(S.begin(), S.end());
    sort(E.begin(), E.end());

    int maxTeam = 0;
    for (int i = 0; i < n; ++i) {
        // number of intervals that started on/before end[i]
        int a = upper_bound(S.begin(), S.end(), endTime[i]) - S.begin();
        // number of intervals that ended strictly before start[i]
        int b = upper_bound(E.begin(), E.end(), startTime[i] - 1) - E.begin();
        int team = a - b;
        maxTeam = max(maxTeam, team);
    }
    return maxTeam;
}

int main() {
    vector<int> startTime = {1, 6, 4, 3, 1};
    vector<int> endTime   = {2, 7, 5, 8, 12};
    cout << getMaximumTeamSize(startTime, endTime) << endl; // should output 3
    return 0;
}

