import java.util.PriorityQueue;

public class ScratchPad {

    public static int countTurns(int[] sticks) {
        if (sticks == null || sticks.length == 0) {
            return 0;
        }

        PriorityQueue<Integer> pq = new PriorityQueue<>();
        for (int stick : sticks) {
            pq.add(stick);
        }

        int turns = 0;
        while (!pq.isEmpty()) {
            int turnCount = pq.size(); // Number of sticks in this turn
            int smallestStick = pq.poll();

            for (int i = 1; i < turnCount; i++) { // Start from 1 because smallest stick is already polled
                int currentStick = pq.poll() - smallestStick;
                if (currentStick > 0) {
                    pq.add(currentStick);
                }
            }
            turns++;
        }

        return turns+1;
    }

    public static void main(String[] args) {
        System.out.println("Turns for [1, 2, 3, 4]: " + countTurns(new int[]{1, 2, 3, 4}));
        // Add more test cases as needed
    }
}


