import java.util.Arrays;
import java.util.Comparator;
import java.util.PriorityQueue;

public class ScratchPad {

    public static int[] findMaxOverlapInterval(int[][] intervals) {
        if (intervals.length == 0) {
            return new int[] {0, 0};
        }

        // Sort the intervals by start time
        Arrays.sort(intervals, new Comparator<int[]>() {
            @Override
            public int compare(int[] a, int[] b) {
                return a[0] - b[0];
            }
        });

        // Min heap to store end times of ongoing intervals
        PriorityQueue<Integer> endTimeHeap = new PriorityQueue<>();

        int maxOverlap = 0;
        int overlapStart = 0;
        int overlapEnd = 0;

        for (int[] interval : intervals) {
            // Remove all intervals that have ended
            while (!endTimeHeap.isEmpty() && endTimeHeap.peek() <= interval[0]) {
                endTimeHeap.poll();
            }

            // Add the current interval's end time
            endTimeHeap.add(interval[1]);

            // Check if current overlap is greater than maxOverlap
            if (endTimeHeap.size() > maxOverlap) {
                maxOverlap = endTimeHeap.size();
                overlapStart = interval[0];
                overlapEnd = endTimeHeap.peek();
            }
        }

        return new int[] {overlapStart, overlapEnd};
    }

    public static void main(String[] args) {
        int[][] intervals = {{1, 3}, {2, 3}, {1, 4}};

        int[] maxOverlapInterval = findMaxOverlapInterval(intervals);
        System.out.println("Maximum overlap interval: [" + maxOverlapInterval[0] + ", " + maxOverlapInterval[1] + "]");
    }
}


