package main

import (
	"fmt"
)

func mylogic(input []int) int {
	mp := make(map[int]bool)
	for _, val := range input {
		mp[val] = true
	}
	return len(mp)
}
func main() {
	testcases := []struct {
		input  []int
		output int
	}{
		{
			input:  []int{1, 2, 3, 4, 5},
			output: 5,
		},
		{
			input:  []int{1, 1, 1, 1, 1},
			output: 1,
		},
		{
			input:  []int{1, 2, 2, 2, 1},
			output: 2,
		},
		{
			input:  []int{939, 93, 1, 1, 1, 2, 21, 21},
			output: 5,
		},
	}

	for i, val := range testcases {
		ans := mylogic(val.input)
		if ans != val.output {
			fmt.Printf("testcase: %s failed", i)
		}
	}
}


